package polymarket

import (
	"github.com/ethereum/go-ethereum/common"
)

// SampleTx represents a real Polymarket transaction to replay.
type SampleTx struct {
	// OriginalHash is the original transaction hash on Polygon
	OriginalHash string
	// BlockNumber is the original block number on Polygon
	BlockNumber uint64
	// From is the operator EOA that sent the transaction
	From common.Address
	// To is the target contract (should always be FeeModule)
	To common.Address
	// Calldata is the full transaction input data
	Calldata []byte
	// GasLimit is the original gas limit
	GasLimit uint64
	// Description is a human-readable description of the transaction
	Description string
}

// SampleTransactions contains real Polymarket matchOrders transactions from Polygon mainnet.
